/* ============================================
   GetOTTs — Single Product Page Router v3
   SEO-optimized, live-catalog-first, slug-aware
   ============================================ */

document.addEventListener('DOMContentLoaded', async () => {
    // 1. Extract slug from URL
    const path = window.location.pathname; 
    const parts = path.split('/').filter(p => p);
    
    let slug = '';
    if (parts.length >= 2 && parts[0] === 'product') {
        slug = parts[1];
    } else if (parts.length === 1) {
        // Direct SEO product URL (e.g. /netflix)
        slug = parts[0];
    } else {
        showError('Invalid Product URL');
        return;
    }

    try {
        // ── CRITICAL: Ensure live catalog is loaded BEFORE any lookup ──
        // bundle.min.js also calls syncCatalogFromCloud on DOMContentLoaded,
        // but there's a race condition. We explicitly await it here.
        if (typeof syncCatalogFromCloud === 'function') {
            await syncCatalogFromCloud();
        }

        // Wait for global overrides to sync so we always have the latest prices
        if (typeof fetchGlobalOverrides === 'function') {
            await fetchGlobalOverrides();
        }

        let product = null;
        let fullProd = null; // The raw catalog product with variants

        // ── Find product from live catalog ──
        if (typeof getAllProducts === 'function') {
            const allProducts = getAllProducts().filter(p => p.isActive !== false);
            
            // Try multiple matching strategies:
            // 1. Exact ID match (covers both clean slugs like "netflix" and legacy IDs like "custom-moat4dtm")
            let rawProd = allProducts.find(p => p.id === slug);
            
            // 2. Try slug field if present (for products that have a separate slug property)
            if (!rawProd) {
                rawProd = allProducts.find(p => p.slug === slug);
            }
            
            // 3. Try name-based match for SEO URLs (e.g. /netflix matches "Netflix")
            if (!rawProd) {
                const slugLower = slug.toLowerCase().replace(/-/g, ' ');
                rawProd = allProducts.find(p => 
                    p.name && p.name.toLowerCase().replace(/[^a-z0-9 ]/g, '').trim() === slugLower
                );
            }
            
            // 4. Try partial name match as last resort (e.g. /prime-video matches "Amazon Prime")
            if (!rawProd) {
                const slugLower = slug.toLowerCase();
                rawProd = allProducts.find(p => {
                    if (!p.name) return false;
                    const nameSlug = p.name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
                    return nameSlug === slugLower;
                });
            }

            if (rawProd) {
                const localProj = typeof getMergedProduct === 'function' ? getMergedProduct(rawProd) : rawProd;
                
                // If admin hides the product, treat as 404
                if (localProj.isActive === false) {
                    throw new Error('Product is currently hidden or disabled.');
                }

                fullProd = localProj;
                const dv = localProj.variants && localProj.variants.length > 0 ? localProj.variants[0] : {};
                const totalStock = localProj.variants ? localProj.variants.reduce((a, v) => a + (v.stock || 0), 0) : 99;

                product = {
                    name: localProj.name,
                    slug: localProj.id,
                    description: localProj.description || localProj.text,
                    price: dv.price || 99,
                    original_price: dv.originalPrice || 199,
                    features: Array.isArray(localProj.features) ? localProj.features : (localProj.features?.shared || []),
                    is_featured: localProj.isHot,
                    live_stock: totalStock,
                    img: localProj.img,
                    platform: {
                        category: localProj.category || 'streaming',
                        logo_url: localProj.img,
                        slug: localProj.id
                    }
                };
            }
        }

        // If not found in catalog at all, show clean 404
        if (!product) {
            throw new Error('This product does not exist in our catalog.');
        }
        
        // 2. SEO — Dynamic meta tags & structured data
        document.title = `Buy ${product.name} Cheap | ${product.name} Subscription at Best Price — GetOTTs`;
        
        // Update meta description
        let metaDesc = document.querySelector('meta[name="description"]');
        if (metaDesc) metaDesc.content = `Buy ${product.name} subscription at cheapest price in India. Starting from ₹${product.price}/mo. Instant delivery, 24/7 support. Trusted by 1000+ customers.`;
        
        // Update canonical URL
        let canonical = document.querySelector('link[rel="canonical"]');
        if (canonical) canonical.href = `https://getotts.com/product/${product.slug}`;

        // Update Open Graph
        const ogTitle = document.querySelector('meta[property="og:title"]');
        if (ogTitle) ogTitle.content = `Buy ${product.name} Cheap — GetOTTs`;
        const ogDesc = document.querySelector('meta[property="og:description"]');
        if (ogDesc) ogDesc.content = `Get ${product.name} at ₹${product.price}/mo. Cheapest in India!`;
        const ogUrl = document.querySelector('meta[property="og:url"]');
        if (ogUrl) ogUrl.content = `https://getotts.com/product/${product.slug}`;
        const ogImage = document.querySelector('meta[property="og:image"]');
        if (ogImage && product.img) ogImage.content = product.img.startsWith('http') ? product.img : `https://getotts.com/${product.img}`;

        // Update JSON-LD schema
        const schemaEl = document.getElementById('productSchema');
        if (schemaEl) {
            schemaEl.textContent = JSON.stringify({
                "@context": "https://schema.org",
                "@type": "Product",
                "name": product.name,
                "description": product.description || `Buy ${product.name} subscription at best price`,
                "image": product.img ? (product.img.startsWith('http') ? product.img : `https://getotts.com/${product.img}`) : '',
                "brand": { "@type": "Brand", "name": product.name },
                "offers": {
                    "@type": "Offer",
                    "priceCurrency": "INR",
                    "price": String(product.price),
                    "availability": "https://schema.org/InStock",
                    "url": `https://getotts.com/product/${product.slug}`,
                    "seller": { "@type": "Organization", "name": "GetOTTs" }
                },
                "aggregateRating": {
                    "@type": "AggregateRating",
                    "ratingValue": "4.9",
                    "reviewCount": "1000",
                    "bestRating": "5"
                }
            });
        }

        // 3. Hydrate the DOM
        
        // Breadcrumbs
        const categoryName = product.platform?.category || 'streaming';
        const bcCat = document.getElementById('bcCategory');
        const catUrlMap = { 'streaming': '/streaming', 'music': '/music', 'ai': '/ai-tools', 'vpn': '/vpn', 'gift-cards': '/gift-cards' };
        bcCat.textContent = categoryName.charAt(0).toUpperCase() + categoryName.slice(1).replace('-', ' ');
        bcCat.href = catUrlMap[categoryName] || '/' + categoryName;
        document.getElementById('bcProduct').textContent = product.name;
        
        // Image handling
        let imgUrl = product.img || product.platform?.logo_url;
        if (!imgUrl) {
            imgUrl = `/assets/images/${product.platform?.slug || 'netflix'}.png`;
        }
        // Ensure path is absolute (fixes /product/assets/... issue)
        if (imgUrl && !imgUrl.startsWith('http') && !imgUrl.startsWith('/')) {
            imgUrl = '/' + imgUrl;
        }
        const productImg = document.getElementById('productImage');
        productImg.src = imgUrl;
        productImg.alt = `${product.name} subscription - buy cheap at GetOTTs`;
        
        // Titles and Prices
        document.getElementById('productTitle').textContent = product.name;
        document.getElementById('productPrice').textContent = `₹${product.price}`;
        
        const origPrice = document.getElementById('productOriginalPrice');
        const discBadge = document.getElementById('productDiscount');
        
        if (product.original_price && product.original_price > product.price) {
            origPrice.textContent = `₹${product.original_price}`;
            const discountPct = Math.round(((product.original_price - product.price) / product.original_price) * 100);
            discBadge.textContent = `${discountPct}% OFF`;
        } else {
            origPrice.style.display = 'none';
            discBadge.style.display = 'none';
        }
        
        document.getElementById('productDesc').textContent = product.description || 'Premium subscription with instant digital delivery and warranty.';
        
        // Stock Status
        const stockEl = document.getElementById('stockStatus');
        const buyBtn = document.getElementById('buyNowBtn');
        
        if (product.live_stock > 0 || product.stock_count > 0) {
            stockEl.innerHTML = `<i data-lucide="check-circle-2"></i> In Stock`;
        } else {
            stockEl.className = 'stock-status low';
            stockEl.innerHTML = `<i data-lucide="alert-circle"></i> Out of Stock`;
            buyBtn.disabled = true;
            buyBtn.style.opacity = 0.5;
            buyBtn.innerHTML = 'Out of Stock';
        }
        
        // Features List
        const featuresContainer = document.getElementById('productFeatures');
        const featuresJson = typeof product.features === 'string' ? JSON.parse(product.features) : product.features;
        
        if (featuresJson && featuresJson.length) {
            featuresContainer.innerHTML = featuresJson.map(f => `
                <div class="feature-item">
                    <i data-lucide="check"></i> ${f}
                </div>
            `).join('');
        }
        
        // Variant selectors (use fullProd which has the complete variant array)
        const variantContainer = document.getElementById('productVariantSelectors');
        let currentSku = product.slug;

        if (fullProd && fullProd.variants) {
            // Function to re-render selectors and pricing
            const renderVariants = (selAccess, selQual, selDur) => {
                const cv = findVariant(fullProd, selAccess, selQual, selDur) || getDefaultVariant(fullProd);
                currentSku = cv.sku;

                // Update Pricing
                document.getElementById('productPrice').textContent = `₹${cv.price}`;
                const origPrice = document.getElementById('productOriginalPrice');
                const discBadge = document.getElementById('productDiscount');
                if (cv.originalPrice > cv.price) {
                    origPrice.textContent = `₹${cv.originalPrice}`;
                    const discountPct = Math.round(((cv.originalPrice - cv.price) / cv.originalPrice) * 100);
                    discBadge.textContent = `${discountPct}% OFF`;
                    origPrice.style.display = 'inline';
                    discBadge.style.display = 'inline-block';
                } else {
                    origPrice.style.display = 'none';
                    discBadge.style.display = 'none';
                }

                // Render Pickers (access type auto-selected, no UI toggle)
                let html = '';

                const qTypes = getQualities(fullProd, cv.accessType);
                if (qTypes && qTypes.length > 1) {
                    html += `<div style="display:flex; flex-direction:column; gap:8px;">
                        <span style="font-size:0.85rem; font-weight:600; color:var(--gray-600);">Quality</span>
                        <div class="v-selector" style="display:flex; gap:8px; flex-wrap:wrap;">
                        ${qTypes.map(q => `<button class="v-pill ${q === cv.quality ? 'active' : ''}" style="padding:6px 12px; border:1px solid ${q===cv.quality?'var(--accent)':'var(--gray-200)'}; border-radius:8px; background:${q===cv.quality?'var(--accent)':'var(--white)'}; color:${q===cv.quality?'var(--white)':'var(--gray-700)'}; cursor:pointer;" onclick="window.updateProductSelection('${cv.accessType}', '${q}', ${cv.duration})">${q}</button>`).join('')}
                        </div></div>`;
                }

                const dTypes = getDurations(fullProd, cv.accessType, cv.quality);
                if (dTypes.length > 1) {
                    html += `<div style="display:flex; flex-direction:column; gap:8px;">
                        <span style="font-size:0.85rem; font-weight:600; color:var(--gray-600);">Duration</span>
                        <div class="v-selector" style="display:flex; gap:8px; flex-wrap:wrap;">
                        ${dTypes.map(d => {
                            const lbl = d >= 24 ? `${d/12}Y` : d >= 12 ? '1Y' : `${d}M`;
                            return `<button class="v-pill ${d === cv.duration ? 'active' : ''}" style="padding:6px 12px; border:1px solid ${d===cv.duration?'var(--accent)':'var(--gray-200)'}; border-radius:8px; background:${d===cv.duration?'var(--accent)':'var(--white)'}; color:${d===cv.duration?'var(--white)':'var(--gray-700)'}; cursor:pointer;" onclick="window.updateProductSelection('${cv.accessType}', '${cv.quality}', ${d})">${lbl}</button>`;
                        }).join('')}
                        </div></div>`;
                }
                variantContainer.innerHTML = html;
            };

            const dv = getDefaultVariant(fullProd);
            renderVariants(dv.accessType, dv.quality, dv.duration);

            window.updateProductSelection = (a, q, d) => {
                // Handle case where JS null was stringified to 'null' in onclick template
                let newA = a, newQ = (q === 'null' ? null : q), newD = d;
                
                const p = fullProd;
                const availQuals = getQualities(p, newA);
                if (availQuals && !availQuals.includes(newQ)) newQ = availQuals[0];
                const availDurs = getDurations(p, newA, newQ);
                if (!availDurs.includes(newD)) newD = availDurs[0];
                
                renderVariants(newA, newQ, newD);
            };
        } else {
            variantContainer.style.display = 'none';
        }
        
        // Buy Button Action
        buyBtn.addEventListener('click', () => {
            window.location.href = `/checkout?buy_now=${currentSku}`;
        });

        // Add to Cart Button
        const cartBtnEl = document.getElementById('addToCartBtn');
        if(cartBtnEl) {
            cartBtnEl.addEventListener('click', () => {
                if (typeof addToCart === 'function') {
                    addToCart(currentSku);
                    // Flash success
                    cartBtnEl.innerHTML = `<i data-lucide="check"></i> Added`;
                    cartBtnEl.classList.add('btn-success');
                    setTimeout(() => {
                        cartBtnEl.innerHTML = `<i data-lucide="shopping-bag"></i> Add to Cart`;
                        cartBtnEl.classList.remove('btn-success');
                        lucide.createIcons();
                    }, 2000);
                } else {
                    window.location.href = `/checkout?buy_now=${currentSku}`;
                }
            });
        }

        // Render Reviews
        const reviewsContainer = document.getElementById('productReviewsGrid');
        if (reviewsContainer && typeof REVIEWS !== 'undefined') {
            const prodReviews = REVIEWS.filter(r => r.platform.toLowerCase().includes(product.name.toLowerCase().split(' ')[0]));
            const fallbackReviews = [
                { stars: 5, text: `Got the credentials instantly after payment! Works perfectly as described without any issues. Saved a lot compared to original prices. Highly recommend!`, initial: 'R', name: 'Rahul V.' },
                { stars: 5, text: `Absolutely brilliant service. The delivery was super fast and the customer support team on WhatsApp was very helpful in setting everything up. Will buy again!`, initial: 'A', name: 'Ankita P.' },
                { stars: 4, text: `Smooth transaction and immediate access. The shared profile works seamlessly. The only minor delay was my payment gateway, but GetOTTs delivered instantly.`, initial: 'M', name: 'Manoj S.' }
            ];
            const displayReviews = prodReviews.length > 0 ? prodReviews : fallbackReviews;
            
            reviewsContainer.innerHTML = displayReviews.map(r => `
                <div style="background:var(--white); border:1px solid var(--gray-100); padding:20px; border-radius:12px; box-shadow:0 2px 8px rgba(0,0,0,0.02);">
                    <div style="display:flex; gap:4px; color:var(--accent); margin-bottom:12px; font-size:0.9rem;">
                        ${Array.from({length: 5}).map((_, i) => i < r.stars ? '★' : '☆').join('')}
                    </div>
                    <p style="font-size:0.95rem; color:var(--gray-700); line-height:1.5; margin-bottom:16px;">"${r.text}"</p>
                    <div style="display:flex; align-items:center; gap:12px;">
                        <div style="width:36px; height:36px; border-radius:50%; background:var(--blue-100); color:var(--blue-700); display:flex; align-items:center; justify-content:center; font-weight:700;">
                            ${r.initial}
                        </div>
                        <div>
                            <div style="font-size:0.9rem; font-weight:600; color:var(--gray-900);">${r.name}</div>
                            <div style="font-size:0.8rem; color:var(--gray-500);"><i data-lucide="check-circle-2" style="width:12px; height:12px; display:inline;"></i> Verified Buyer</div>
                        </div>
                    </div>
                </div>
            `).join('');
        }
        
        // Finalize DOM
        lucide.createIcons();
        document.getElementById('loadingState').style.display = 'none';
        const container = document.getElementById('productContainer');
        container.style.display = 'block';
        setTimeout(() => container.classList.add('loaded'), 10);
        
    } catch (err) {
        console.error(err);
        showError(`Product not found or unavailable. <br><small style="color:var(--gray-500)">Try browsing from the <a href="/">homepage</a>.</small><br><br><small style="color:var(--danger)">Error: ${err.message}</small>`);
    }
});

function toggleAccordion(btn) {
    const item = btn.parentElement;
    item.classList.toggle('active');
}

function showError(msg) {
    document.getElementById('loadingState').innerHTML = `
        <i data-lucide="x-circle" style="color:var(--danger); width:40px; height:40px;"></i>
        <p style="margin-top: 16px; color: var(--gray-800);">${msg}</p>
        <a href="/" class="btn btn-outline" style="margin-top: 12px; display:inline-block;">Return Home</a>
    `;
    lucide.createIcons();
}
